## Config File Format

### .aadcrc (TOML)

```toml
# aadc configuration file
# Place in project root or home directory

# Processing options
min_score = 0.5           # or use preset
preset = "normal"         # strict | normal | aggressive | relaxed
max_iters = 10
tab_width = 4

# Output options
verbose = false
color = "auto"            # auto | always | never
json = false

# File handling
backup = false
backup_suffix = ".bak"

# Recursive mode defaults
recursive = false
glob = "*.txt,*.md"
gitignore = true
max_depth = 0

# Watch mode
debounce_ms = 500

# Advanced
all = false               # Process low-confidence blocks
```

## Implementation

### Config Search and Loading

```rust
use std::path::{Path, PathBuf};
use serde::Deserialize;

const CONFIG_FILENAMES: &[&str] = &[".aadcrc", ".aadcrc.toml", "aadcrc.toml"];

#[derive(Debug, Deserialize, Default)]
#[serde(default)]
pub struct FileConfig {
    pub min_score: Option<f64>,
    pub preset: Option<String>,
    pub max_iters: Option<usize>,
    pub tab_width: Option<usize>,
    pub verbose: Option<bool>,
    pub color: Option<String>,
    pub json: Option<bool>,
    pub backup: Option<bool>,
    pub backup_suffix: Option<String>,
    pub recursive: Option<bool>,
    pub glob: Option<String>,
    pub gitignore: Option<bool>,
    pub max_depth: Option<usize>,
    pub debounce_ms: Option<u64>,
    pub all: Option<bool>,
}

pub fn find_config_file(start_dir: &Path) -> Option<PathBuf> {
    test_log!("DEBUG", "Searching for config file from: {:?}", start_dir);

    let mut current = start_dir.to_path_buf();

    // Search up directory tree
    loop {
        for filename in CONFIG_FILENAMES {
            let config_path = current.join(filename);
            if config_path.exists() {
                test_log!("INFO", "Found config file: {:?}", config_path);
                return Some(config_path);
            }
        }

        if !current.pop() {
            break;
        }
    }

    // Check home directory
    if let Some(home) = dirs::home_dir() {
        for filename in CONFIG_FILENAMES {
            let config_path = home.join(filename);
            if config_path.exists() {
                test_log!("INFO", "Found config file in home: {:?}", config_path);
                return Some(config_path);
            }
        }
    }

    test_log!("DEBUG", "No config file found");
    None
}

pub fn load_config_file(path: &Path) -> Result<FileConfig, Error> {
    test_log!("INFO", "Loading config from: {:?}", path);

    let content = std::fs::read_to_string(path)?;
    let config: FileConfig = toml::from_str(&content)
        .map_err(|e| Error::ConfigParse(format!("Invalid TOML: {}", e)))?;

    test_log!("DEBUG", "Loaded config: {:?}", config);
    Ok(config)
}
```

### Config Merging (CLI overrides file)

```rust
impl Config {
    pub fn with_file_config(mut self, file_config: FileConfig) -> Self {
        test_log!("DEBUG", "Merging file config with CLI args");

        // Only apply file config values if CLI didn't override
        if self.min_score_from_cli.is_none() {
            if let Some(score) = file_config.min_score {
                self.min_score = score;
            }
            if let Some(preset) = file_config.preset {
                self.preset = Some(preset.parse().ok()?);
            }
        }

        if self.max_iters_from_cli.is_none() {
            if let Some(iters) = file_config.max_iters {
                self.max_iters = iters;
            }
        }

        if self.tab_width_from_cli.is_none() {
            if let Some(width) = file_config.tab_width {
                self.tab_width = width;
            }
        }

        // Boolean flags: CLI explicit value overrides file
        if !self.verbose_from_cli {
            self.verbose = file_config.verbose.unwrap_or(self.verbose);
        }

        if !self.backup_from_cli {
            self.backup = file_config.backup.unwrap_or(self.backup);
        }

        if self.backup_suffix_from_cli.is_none() {
            if let Some(suffix) = file_config.backup_suffix {
                self.backup_suffix = suffix;
            }
        }

        // Recursive mode options
        if !self.recursive_from_cli {
            self.recursive = file_config.recursive.unwrap_or(self.recursive);
        }

        if self.glob_from_cli.is_none() {
            if let Some(glob) = file_config.glob {
                self.glob = glob;
            }
        }

        // ... continue for other options

        test_log!("DEBUG", "Merged config: {:?}", self);
        self
    }
}
