    config: &Config,
    input: &str,
) -> (String, ProcessingStats) {
    test_log!("INFO", "Processing with line ranges: {:?}", config.lines);

    let lines: Vec<&str> = input.lines().collect();
    let total_lines = lines.len();

    // Determine which lines to process
    let process_mask = if let Some(ref ranges) = config.lines {
        let mut mask = vec![false; total_lines];
        for range in ranges {
            let start = range.start.saturating_sub(1);  // Convert to 0-indexed
            let end = range.end.min(total_lines);
            for i in start..end {
                mask[i] = true;
            }
        }
        mask
    } else {
        vec![true; total_lines]  // Process all
    };

    test_log!("DEBUG", "Process mask: {} lines marked for processing",
        process_mask.iter().filter(|&&b| b).count());

    // Detect blocks only in marked regions
    let blocks = detect_blocks_with_mask(&lines, &process_mask);

    let mut output_lines: Vec<String> = lines.iter().map(|s| s.to_string()).collect();
    let mut stats = ProcessingStats::new();
    stats.total_lines = total_lines;

    for block in blocks {
        // Only process if block overlaps with ranges
        let block_in_range = (block.start..block.end).any(|i| process_mask.get(i).copied().unwrap_or(false));

        if !block_in_range {
            test_log!("DEBUG", "Skipping block at lines {}-{}: outside requested range", block.start + 1, block.end + 1);
            stats.blocks_skipped += 1;
            continue;
        }

        stats.blocks_found += 1;

        if block.confidence < config.effective_min_score() {
            stats.blocks_skipped += 1;
            continue;
        }

        stats.blocks_processed += 1;

        let (revised, revisions, skipped) = correct_block(config, &block, &output_lines);
        stats.revisions_applied += revisions;
        stats.revisions_skipped += skipped;

        for (i, line) in revised.iter().enumerate() {
            if block.start + i < output_lines.len() {
                output_lines[block.start + i] = line.clone();
            }
        }
    }

    (output_lines.join("\n"), stats)
}
```

### Verbose Output for Range Processing

```rust
pub fn print_range_info(config: &Config, total_lines: usize, colors: &VerboseColors) {
    if let Some(ref ranges) = config.lines {
        let covered: usize = ranges.iter()
            .map(|r| r.end.min(total_lines).saturating_sub(r.start.saturating_sub(1)))
            .sum();

        let range_strs: Vec<String> = ranges.iter()
            .map(|r| {
                if r.end == usize::MAX {
                    format!("{}-", r.start)
                } else if r.start == r.end {
                    format!("{}", r.start)
                } else {
                    format!("{}-{}", r.start, r.end)
                }
            })
            .collect();

        eprintln!(
            "{}Line ranges:{} {} ({} of {} lines)",
            colors.header.render_str(""),
            Style::reset(),
            range_strs.join(", "),
            covered,
            total_lines
        );
    }
}
```

## Edge Cases

1. **Range exceeds file length**: Clamp to actual file length
2. **Overlapping ranges**: Merge automatically
3. **Single line**: "42" means just line 42
4. **Open-ended ranges**: "50-" or "-100" supported
5. **Zero or negative**: Error with helpful message
6. **Empty ranges**: Process nothing, output unchanged

