fn test_diff_output_format() {
    let original = "+---+\n| a|\n+---+\n";
    let modified = "+---+\n| a |\n+---+\n";

    let mut output = Vec::new();
    print_diff_to(&original, &modified, Path::new("test.txt"), &mut output);
    let diff_str = String::from_utf8(output).unwrap();

    assert!(diff_str.contains("--- test.txt"));
    assert!(diff_str.contains("+++ test.txt (corrected)"));
    assert!(diff_str.contains("-| a|"));
    assert!(diff_str.contains("+| a |"));
