    let original = "line1\nline2\n+---+\n| a|\n+---+\nline6\n";
    let modified = "line1\nline2\n+---+\n| a |\n+---+\nline6\n";

    let mut output = Vec::new();
    print_diff_to(&original, &modified, Path::new("test.txt"), &mut output);
    let diff_str = String::from_utf8(output).unwrap();

    // Should have hunk header with line numbers
    assert!(diff_str.contains("@@"));
    assert!(diff_str.contains("4")); // Line 4 changed
}
